class Solution {
public:
    string categorizeBox(int length, int width, int height, int mass) {
        if (length >= 10000 || width >= 10000 || height >= 10000 || length * width * height >= 10000000000) {
            if (mass >= 100) {
                return "Both";
            } else {
                return "Bulky";
            }
        } else if (mass >= 100) {
            return "Heavy";
        } else {
            return "Neither";
        }
    }
};
